import { useEffect, useState } from 'react';
import { fetchGroups } from '../services/api';
import '../styles/Groups.css'; // tu peux adapter ou créer un fichier spécifique si besoin

export default function MyGroups({ currentUser }) {
    const [myGroups, setMyGroups] = useState([]);

    useEffect(() => {
        // Récupérer tous les groupes puis filtrer ceux où l'utilisateur est membre
        fetchGroups().then(groups => {
            const filtered = groups.filter(group =>
                group.members.some(member => member.email === currentUser?.email)
            );
            setMyGroups(filtered);
        });
    }, [currentUser]);

    return (
        <div className="groups-container">
            <h1 className="groups-title">Mes Groupes</h1>
            <div className="groups-grid">
                {myGroups.map(group => (
                    <div key={group.id} className="group-card">
                        <div className="group-info">
                            <h2 className="group-name">{group.name}</h2>
                            <p className="group-members">
                                {group.members.length} membres
                            </p>
                            <ul className="member-list">
                                {group.members.map((m, i) => (
                                    <li key={i}>{m.name}</li>
                                ))}
                            </ul>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}
